<?php function hitungAngsuranFlat(float $pokok,int $tenor,float $bungaTahunan):array{$bungaPerBulanAsli=($pokok*($bungaTahunan/100))/12;$pokokPerBulanAsli=$pokok/$tenor;$bungaPerBulan=ceil($bungaPerBulanAsli/100)*100;$pokokPerBulan=ceil($pokokPerBulanAsli/100)*100;$angsuranBulanan=$pokokPerBulan+$bungaPerBulan;$totalBunga=$bungaPerBulan*$tenor;return['angsuran_bulanan'=>$angsuranBulanan,'total_bunga'=>$totalBunga];}function hitungAngsuranAnuitas(float $pokok,int $tenor,float $bungaBulananPersen):array{if($bungaBulananPersen<=0){$angsuranBulanan=$pokok/$tenor;$totalBunga=0;}else{$i=$bungaBulananPersen/100;$angsuranBulananAsli=$pokok*($i*pow(1+$i,$tenor))/(pow(1+$i,$tenor)-1);$angsuranBulanan=round($angsuranBulananAsli);$sisa=$pokok;$totalBunga=0;for($j=1;$j<=$tenor;$j++){$bunga=round($sisa*$i);$totalBunga+=$bunga;if($j==$tenor){$pokokAngsuran=$sisa;}else{$pokokAngsuran=$angsuranBulanan-$bunga;}$sisa-=$pokokAngsuran;}}return['angsuran_bulanan'=>$angsuranBulanan??($pokok/$tenor),'total_bunga'=>$totalBunga];}function cariBungaAnuitasEkuivalen(float $pokok,int $tenor,float $targetTotalBungaFlat):float{$bawah=0.0;$atas=100.0;$bungaAnuitasBulanan=0.0;$presisi=0.00001;$iterasiMaks=100;for($i=0;$i<$iterasiMaks;$i++){$tengah=($bawah+$atas)/2;$hasilAnuitas=hitungAngsuranAnuitas($pokok,$tenor,$tengah);$selisihBunga=$hasilAnuitas['total_bunga']-$targetTotalBungaFlat;if(abs($selisihBunga)<$presisi){$bungaAnuitasBulanan=$tengah;break;}if($selisihBunga<0){$bawah=$tengah;}else{$atas=$tengah;}$bungaAnuitasBulanan=$tengah;}return $bungaAnuitasBulanan*12;}function generateTabelAmortisasiAnuitas(float $pokok,int $tenor,float $bungaBulananPersen,float $angsuranBulananAsli):array{$rows=[];$sisaPinjaman=$pokok;$i=$bungaBulananPersen/100;$angsuranBulanan=round($angsuranBulananAsli);$totalAngsuran=0;$totalPokok=0;$totalBunga=0;for($bulan=1;$bulan<=$tenor;$bulan++){$bunga=round($sisaPinjaman*$i);if($bulan===$tenor){$pokokAngsuran=$sisaPinjaman;$angsuran=$pokokAngsuran+$bunga;}else{$angsuran=$angsuranBulanan;$pokokAngsuran=$angsuran-$bunga;}$sisaPinjaman-=$pokokAngsuran;if(abs($sisaPinjaman)<0.01){$sisaPinjaman=0;}$totalAngsuran+=$angsuran;$totalPokok+=$pokokAngsuran;$totalBunga+=$bunga;$rows[]=['bulan'=>$bulan,'angsuran'=>$angsuran,'pokok'=>$pokokAngsuran,'bunga'=>$bunga,'sisa_pinjaman'=>$sisaPinjaman];}return['rows'=>$rows,'totals'=>['angsuran'=>$totalAngsuran,'pokok'=>$totalPokok,'bunga'=>$totalBunga]];}function generateTabelAmortisasiFlat(float $pokok,int $tenor,float $bungaTahunan,float $angsuranBulananAsli):array{$rows=[];$sisaPinjaman=$pokok;$pokokPerBulanAsli=$pokok/$tenor;$bungaPerBulanAsli=($pokok*($bungaTahunan/100))/12;$pokokPerBulan=ceil($pokokPerBulanAsli/100)*100;$bungaPerBulan=ceil($bungaPerBulanAsli/100)*100;$angsuranBulanan=$pokokPerBulan+$bungaPerBulan;$totalAngsuran=0;$totalPokok=0;$totalBunga=0;for($bulan=1;$bulan<=$tenor;$bulan++){if($bulan===$tenor){$pokokSaatIni=$sisaPinjaman;$bungaSaatIni=$bungaPerBulan;$angsuranSaatIni=$pokokSaatIni+$bungaSaatIni;}else{$pokokSaatIni=$pokokPerBulan;$bungaSaatIni=$bungaPerBulan;$angsuranSaatIni=$angsuranBulanan;}$sisaPinjaman-=$pokokSaatIni;if(abs($sisaPinjaman)<0.01){$sisaPinjaman=0;}$totalAngsuran+=$angsuranSaatIni;$totalPokok+=$pokokSaatIni;$totalBunga+=$bungaSaatIni;$rows[]=['bulan'=>$bulan,'angsuran'=>$angsuranSaatIni,'pokok'=>$pokokSaatIni,'bunga'=>$bungaSaatIni,'sisa_pinjaman'=>$sisaPinjaman];}return['rows'=>$rows,'totals'=>['angsuran'=>$totalAngsuran,'pokok'=>$totalPokok,'bunga'=>$totalBunga]];}$hasilKalkulasi=null;$input=['nominal_pinjaman'=>10000000,'tenor_bulan'=>12,'suku_bunga_tahunan'=>15,'jenis_bunga'=>'flat'];if(isset($_GET['nominal_pinjaman'])){$input['nominal_pinjaman']=(float)($_GET['nominal_pinjaman']??0);$input['tenor_bulan']=(int)($_GET['tenor_bulan']??0);$input['suku_bunga_tahunan']=ceil((float)($_GET['suku_bunga_tahunan']??0));$input['jenis_bunga']='flat';$pokok=$input['nominal_pinjaman'];$tenor=$input['tenor_bulan'];$sukuBungaInput=$input['suku_bunga_tahunan'];$jenisBungaInput='flat';$hasilFlat=[];$hasilAnuitas=[];if($input['nominal_pinjaman']>0&&$input['tenor_bulan']>0){$hasilFlat=hitungAngsuranFlat($pokok,$tenor,$sukuBungaInput);$bungaAnuitasEkuivalen=cariBungaAnuitasEkuivalen($pokok,$tenor,$hasilFlat['total_bunga']);$bungaAnuitasEkuivalen=ceil($bungaAnuitasEkuivalen);$hasilAnuitas=hitungAngsuranAnuitas($pokok,$tenor,$bungaAnuitasEkuivalen/12);$sukuBungaFlatFinal=$sukuBungaInput;$sukuBungaAnuitasFinal=$bungaAnuitasEkuivalen;$tabelAmortisasiFlat=generateTabelAmortisasiFlat($pokok,$tenor,$sukuBungaFlatFinal,$hasilFlat['angsuran_bulanan']);$tabelAmortisasiAnuitas=generateTabelAmortisasiAnuitas($pokok,$tenor,$sukuBungaAnuitasFinal/12,$hasilAnuitas['angsuran_bulanan']);$hasilKalkulasi=['flat'=>['suku_bunga_tahunan'=>$sukuBungaFlatFinal,'suku_bunga_bulanan'=>$sukuBungaFlatFinal/12,'angsuran_bulanan'=>$tabelAmortisasiFlat['rows'][0]['angsuran']??$hasilFlat['angsuran_bulanan'],'total_bunga'=>$tabelAmortisasiFlat['totals']['bunga']??$hasilFlat['total_bunga'],'amortisasi'=>$tabelAmortisasiFlat],'anuitas'=>['suku_bunga_tahunan'=>$sukuBungaAnuitasFinal,'suku_bunga_bulanan'=>$sukuBungaAnuitasFinal/12,'angsuran_bulanan'=>$tabelAmortisasiAnuitas['rows'][0]['angsuran']??$hasilAnuitas['angsuran_bulanan'],'total_bunga'=>$tabelAmortisasiAnuitas['totals']['bunga']??$hasilAnuitas['total_bunga'],'amortisasi'=>$tabelAmortisasiAnuitas],'input_type'=>'flat','nominal_pinjaman'=>$pokok,'tenor_bulan'=>$tenor];}}function formatRupiah(float $angka):string{return'Rp '.number_format($angka,0,',','.');}function formatPersen(float $angka):string{$formatted=number_format($angka,4,',','.');if(strpos($formatted,',')!==false){$formatted=rtrim($formatted,'0');$formatted=rtrim($formatted,',');}return $formatted.'%';}function formatPersenBulanan(float $angka):string{return number_format($angka,2,',','.').'%';}?>
