el><input type="number" id="tenor_bulan" name="tenor_bulan" class="form-input" value="<?=htmlspecialchars($input['tenor_bulan'])?>" required></div><div class="form-group"><label for="suku_bunga_tahunan">Suku Bunga Flat (% per Tahun)</label><input type="number" step="1" id="suku_bunga_tahunan" name="suku_bunga_tahunan" class="form-input" value="<?=htmlspecialchars($input['suku_bunga_tahunan'])?>" required></div></div><div style="margin-top:2rem;display:flex;gap:.5rem;"><button type="submit" class="submit-button" style="flex:3;margin-top:0;">Hitung Simulasi</button><a href="index.php" class="reset-button" style="flex:1;margin-top:0;">Reset</a></div></form></div><?php if($hasilKalkulasi):?><section class="results-section"><h2>Hasil Perbandingan</h2><div class="comparison-grid"><div class="card"><div class="card-header"><h3>Flat</h3></div><div class="card-body"><div class="card-item"><span>Suku Bunga (p.a.)</span><strong><?=formatPersen($hasilKalkulasi['flat']['suku_bunga_tahunan'])?></strong></div><div class="card-item"><span>Suku Bunga (/bulan)</span><strong><?=formatPersenBulanan($hasilKalkulasi['flat']['suku_bunga_bulanan'])?></strong></div><div class="card-item"><span>Angsuran / Bulan</span><strong><?=formatRupiah($hasilKalkulasi['flat']['angsuran_bulanan'])?></strong></div><div class="card-item"><span>Total Bunga</span><strong><?=formatRupiah($hasilKalkulasi['flat']['total_bunga'])?></strong></div></div></div><div class="card"><div class="card-header"><h3>Anuitas <span class="highlight">(Ekuivalen)</span></h3></div><div class="card-body"><div class="card-item"><span>Suku Bunga (p.a.)</span><strong><?=formatPersen($hasilKalkulasi['anuitas']['suku_bunga_tahunan'])?></strong></div><div class="card-item"><span>Suku Bunga (/bulan)</span><strong><?=formatPersenBulanan($hasilKalkulasi['anuitas']['suku_bunga_bulanan'])?></strong></div><div class="card-item"><span>Angsuran / Bulan</span><strong><?=formatRupiah($hasilKalkulasi['anuitas']['angsuran_bulanan'])?></strong></div><div class="card-item"><span>Total Bunga</span><strong><?=formatRupiah($hasilKalkulasi['anuitas']['total_bunga'])?></strong></div></div></div></div></section><?php endif;?></div></div><?php if($hasilKalkulasi):?><div class="tab-pane" id="detail"><div class="amortization-grid"><div><h3>Detail Angsuran Flat</h3><div class="table-responsive"><table><thead><tr><th>Bln</th><th>Angsuran</th><th>Pokok</th><th>Bunga</th><th>Sisa Pinjaman</th></tr></thead><tbody><?php foreach($hasilKalkulasi['flat']['amortisasi']['rows'] as $row):?><tr><td><?=$row['bulan']?></td><td><?=formatRupiah($row['angsuran'])?></td><td><?=formatRupiah($row['pokok'])?></td><td><?=formatRupiah($row['bunga'])?></td><td><?=formatRupiah($row['sisa_pinjaman'])?></td></tr><?php endforeach;?></tbody><tfoot><tr><td>TOTAL</td><td><?=formatRupiah($hasilKalkulasi['flat']['amortisasi']['totals']['angsuran'])?></td><td><?=formatRupiah($hasilKalkulasi['flat']['amortisasi']['totals']['pokok'])?></td><td><?=formatRupiah($hasilKalkulasi['flat']['amortisasi']['totals']['bunga'])?></td><td></td></tr></tfoot></table></div></div><div><h3>Detail Angsuran Anuitas</h3><div class="table-responsive"><table><thead><tr><th>Bln</th><th>Angsuran</th><th>Pokok</th><th>Bunga</th><th>Sisa Pinjaman</th></tr></thead><tbody><?php foreach($hasilKalkulasi['anuitas']['amortisasi']['rows'] as $row):?><tr><td><?=$row['bulan']?></td><td><?=formatRupiah($row['angsuran'])?></td><td><?=formatRupiah($row['pokok'])?></td><td><?=formatRupiah($row['bunga'])?></td><td><?=formatRupiah($row['sisa_pinjaman'])?></td></tr><?php endforeach;?></tbody><tfoot><tr><td>TOTAL</td><td><?=formatRupiah($hasilKalkulasi['anuitas']['amortisasi']['totals']['angsuran'])?></td><td><?=formatRupiah($hasilKalkulasi['anuitas']['amortisasi']['totals']['pokok'])?></td><td><?=formatRupiah($hasilKalkulasi['anuitas']['amortisasi']['totals']['bunga'])?></td><td></td></tr></tfoot></table></div></div></div></div><?php endif;?></div><?php if($hasilKalkulasi):?><div class="toggle-details-container"><button type="button" id="downloadPdfBtn" class="toggle-button primary">Unduh sebagai PDF</button></div><?php endif;?><div class="disclaimer-section"><p style="margin:0;"><strong>Disclaimer:</strong> Perhitungan pada simulasi ini bersifat estimasi awal dan ditujukan sebagai informasi umum semata. Besaran angsuran, suku bunga, biaya administrasi, serta ketentuan lainnya dapat berubah sewaktu-waktu sesuai dengan kebijakan perbankan yang berlaku dan hasil analisa persetujuan kredit. Untuk mendapatkan kepastian rincian perhitungan dan proses pengajuan fasilitas kredit resmi, silakan mengunjungi atau menghubungi kantor operasional PT BPR ARTHA PAMENANG terdekat.</p></div></main></div><footer><p>© <?=date('Y')?> PT BPR ARTHA PAMENANG | Dibangun oleh Ahli_Prosesor.</p></footer><?php if($hasilKalkulasi):?><script>const kalkulasiData=<?=json_encode($hasilKalkulasi);?>;</script><?php endif;?><script src="script.js?v=<?=time()?>"></script></body></html>
